        if p == "5thRunwayLengthFeet":
            return f"{s}'s fifth runway is {o} feet long"
        if p == "1stRunwayLengthMetre":
            return f"{s}'s first runway is {o} metres long"
        if p == "1stRunwaySurfaceType":
